const users = $input.all().map(i => i.json);
const flat = Array.isArray(users[0]) ? users[0] : users;
const now = new Date();
const atRisk = [];

for (const user of flat) {
  if (!user.email) continue;
  const createdAt = new Date(user.created_at || user.trial_start);
  const daysSinceCreation = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));
  const lastActive = user.last_active_at ? new Date(user.last_active_at) : null;
  const daysSinceActive = lastActive ? Math.floor((now - lastActive) / (1000 * 60 * 60 * 24)) : 999;

  let riskType = null;
  let emailSubject = '';
  let emailBody = '';

  // Trial ending in 1-2 days (day 12-13 of 14-day trial)
  if (user.status === 'trial_ending' || (daysSinceCreation >= 12 && daysSinceCreation <= 13 && !user.is_paying)) {
    riskType = 'trial_ending';
    emailSubject = 'Your BayFlow trial ends soon - don\'t lose your data';
    emailBody = `Hi ${user.name || 'there'},\n\nYour BayFlow trial ends in ${14 - daysSinceCreation} day(s). All your repair orders, customer data, and inspection reports are ready to keep working for you.\n\nUpgrade now to keep everything intact:\nhttps://app.bayflow.com/billing\n\nQuestions? Just reply to this email.\n\n- The BayFlow Team`;
  }
  // Onboarded but not paying
  else if (user.status === 'onboarded_not_paying' && daysSinceCreation > 14) {
    riskType = 'onboarded_not_paying';
    emailSubject = 'We noticed you haven\'t upgraded BayFlow yet';
    emailBody = `Hi ${user.name || 'there'},\n\nYou set up your shop in BayFlow, which is great. We noticed you haven\'t activated a paid plan yet.\n\nIs something holding you back? We\'d love to help. Reply to this email and we\'ll sort it out personally.\n\nOr if you\'re ready: https://app.bayflow.com/billing\n\n- The BayFlow Team`;
  }
  // Inactive 7+ days
  else if (daysSinceActive >= 7 || user.status === 'inactive') {
    riskType = 'inactive_7d';
    emailSubject = 'We miss you at BayFlow';
    emailBody = `Hi ${user.name || 'there'},\n\nIt\'s been a while since you logged into BayFlow. Your shop data is safe and waiting for you.\n\nHere are some things other shops are doing this week:\n- Running digital inspections with photo documentation\n- Tracking parts margins on repair orders\n- Sending professional invoices to customers\n\nLog back in: https://app.bayflow.com\n\n- The BayFlow Team`;
  }

  if (riskType) {
    atRisk.push({
      email: user.email,
      name: user.name || '',
      user_id: user.user_id || user.id,
      riskType,
      emailSubject,
      emailBody,
      daysSinceCreation,
      daysSinceActive
    });
  }
}

return atRisk.length > 0 ? atRisk.map(u => ({ json: u })) : [{ json: { _empty: true, count: 0 } }];

const body = $('Cancellation Webhook').first().json;
const email = body.email || body.user_email || 'unknown';
const reason = body.reason || body.cancellation_reason || 'No reason given';
const userId = body.user_id || body.id || 'unknown';

const emailBody = `Hi ${body.name || 'there'},

We're sorry to see you go. We've cancelled your BayFlow subscription as requested.

Your data will be available for 30 days if you change your mind. Just log back in and reactivate.

If you have a moment, we'd love to know what we could do better. Just reply to this email.

Wishing your shop all the best,
- The BayFlow Team`;

return [{ json: { email, reason, userId, name: body.name || '', emailBody } }];
